/* Tipos, estructuras y enumeraciones */
TaskHandle_t led_handle; 	//FreeRTOS
osThreadId button_handle;	//CMSIS OS

/* Variables globales */
EXTI_Config_t ext_var = { .en = 0 };

//usart2
