SemaphoreHandle_t semButton = NULL;

/* Prototipo de funciones */
void Task_Led(void *params);
void Task_Button(void const *params);


/*CMSIS var*/
osThreadDef(button_name, Task_Button, 2, 0, 1024);

/* Función principal */
int main(void)
{
	BaseType_t status = 0;

	//Usart2 Config
	USARTx_Init(&USART2_Config); //priority  solo en USARTx_Init_IT

	printf("Init Task Creat\r\n");

	//FreeRTOS
	status = xTaskCreate(Task_Led, "Task_Led", 1024, NULL, 2, &led_handle);
	if(status != pdPASS)
	{
		while(1);
	}

	//CMSIS OS
	button_handle = osThreadCreate(osThread(button_name), NULL);
	if(button_handle == NULL)
	{
		while(1);
	}

	//Create Semaph
	semButton = xSemaphoreCreateBinary();

	//Init Scheduler
	osKernelStart(); //CMSIS RTOS
	//vTaskStartScheduler(); //FreeRTOS

	while(1);

}

/* Definición de funciones */

/*
 * @brief
 */

void Task_Led(void *params)
{
	//Config led and initialize
	GPIO_Output_Config(GPIO_LED, PIN_LED, PUPDR_NONE, OSPEEDR_LOW, OTYPER_PP);
	GPIO_Write(GPIO_LED, PIN_LED, 0);
	printf("task led init\r\n");
	while(1)
	{
		//Task is blocking to 2 seconds
		if(xSemaphoreTake(semButton,pdMS_TO_TICKS(2000)))
		{
			GPIO_Write(GPIO_LED, PIN_LED, 1);
			printf("Recibe semaforo\r\n");
		}
		else
		{
			GPIO_Write(GPIO_LED, PIN_LED, 0);
			printf("No se recibe semáforo\r\n");
		}
		vTaskDelay(pdMS_TO_TICKS(1));

	}
}


/*
 * @brief
 */
void Task_Button(void const *params)
{
	//Config button and initialize
	GPIO_Input_Config(GPIO_BUTTON, PIN_BUTTON, PUPDR_NONE, &ext_var);
	printf("task button init\r\n");
	while(1)
	{
		if(GPIO_ReadPin(GPIO_BUTTON, PIN_BUTTON) == 0)
		{
			osDelay(100);
			xSemaphoreGive(semButton);
		}

		osDelay(1);
	}
}

/*******************************/
int __io_putchar(int ch){
#if (USE_SWV== 1)
	ITM_SendChar((uint32_t)ch);
#else
	uint8_t c = ch & 0xFF;
	while(!(USART2->SR & USART_SR_TXE));  //espera hasta que usart este listo para transmitir otro byte
	USART2->DR = c;
#endif
	return ch;
}
